import numpy as np

# {Implement a collaborative decision-making process where trucks prioritize minimizing penalties through consensus by dynamically adjusting influence weights based on historical performance.}
def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    influence_weights = np.ones(len(unvisited_customers))
    estimated_costs = np.zeros(len(unvisited_customers))

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = euclidean_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time

        start_time, end_time = time_windows[i]
        wait_time = max(0, start_time - arrival_time)

        penalty = max(0, 1000 * (arrival_time - end_time))

        estimated_costs[i] = travel_time + wait_time + penalty

    for truck_pos in all_truck_pos:
        for j, customer_pos in enumerate(unvisited_customers):
            if not np.array_equal(truck_pos, cur_truck_pos):
                distance = euclidean_distance(truck_pos, customer_pos)
                influence_weights[j] += 1 / (1 + distance)

    weights_sum = np.sum(influence_weights)
    influence_weights_normalized = influence_weights / weights_sum if weights_sum != 0 else influence_weights

    best_node = np.argmin(estimated_costs * influence_weights_normalized)

    return best_node
